/**
 * Dynamic sidebar factory used by preset-classic's `docs.sidebarPath`.
 *
 * Reads the consumer's docs.config.js from `process.env.DOCS_DIR`
 * (set by the docs CLI) or falls back to `process.cwd()`, then builds
 * one autogenerated sidebar per nav item that declares `docsPath`.
 *
 * Autogenerated sidebars use `dirName` relative to the docs plugin `path`
 * (i.e. relative to <mdxRoot>). So `{ label: 'A', docsPath: 'docs-a' }` maps
 * to sidebar `A = [{ type: 'autogenerated', dirName: 'docs-a' }]`.
 */
const path = require('path');
const fs = require('fs');
const createJiti = require('jiti');

const CONFIG_CANDIDATES = [
  'docs.config.ts',
  'docs.config.mts',
  'docs.config.js',
  'docs.config.cjs',
  'docs.config.mjs',
];

function findConfigFile(siteDir) {
  for (const f of CONFIG_CANDIDATES) {
    const p = path.join(siteDir, f);
    if (fs.existsSync(p)) return p;
  }
  return null;
}

function loadDocsConfig() {
  const siteDir = process.env.DOCS_DIR || process.cwd();
  // If the CLI was invoked with `--config <path>`, DOCS_CONFIG points
  // at the exact file to load — honor it so sidebar generation stays in sync
  // with the nav declared by that config (e.g. a prod variant that overrides nav).
  const envConfig = process.env.DOCS_CONFIG;
  let configPath;
  if (envConfig) {
    configPath = path.isAbsolute(envConfig) ? envConfig : path.resolve(siteDir, envConfig);
    if (!fs.existsSync(configPath)) configPath = null;
  } else {
    configPath = findConfigFile(siteDir);
  }
  if (!configPath) {
    return { sidebars: { main: [{ type: 'autogenerated', dirName: '.' }] } };
  }
  const jiti = createJiti(__filename, { interopDefault: true, cache: false });
  const mod = jiti(configPath);
  const site = mod.default || mod;
  return { site };
}

const { site, sidebars: fallbackSidebars } = loadDocsConfig();
let sidebars;

if (fallbackSidebars) {
  sidebars = fallbackSidebars;
} else {
  sidebars = {};
  const nav = Array.isArray(site && site.nav) ? site.nav : [];
  for (const item of nav) {
    if (!item || typeof item !== 'object') continue;
    if (typeof item.docsPath !== 'string') continue;
    const sidebarId = item.label || item.docsPath;
    sidebars[sidebarId] = [{ type: 'autogenerated', dirName: item.docsPath }];
  }
  if (Object.keys(sidebars).length === 0) {
    sidebars.main = [{ type: 'autogenerated', dirName: '.' }];
  }
}

module.exports = sidebars;
